package com.example.prototype;

import android.content.Context;
import android.content.SharedPreferences;

public class SessionManager {
    private static final String PREF_NAME = "demo_session";
    private static final String KEY_EMAIL = "key_email";
    private static final String KEY_AUTH_TOKEN = "key_auth_token";
    private static final String KEY_LOGGED_IN = "key_logged_in";

    private final SharedPreferences sharedPreferences;

    public SessionManager(Context context) {
        this.sharedPreferences = context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE);
    }

    public void saveLoginSession(String email, String authToken) {
        sharedPreferences.edit()
                .putString(KEY_EMAIL, email)
                .putString(KEY_AUTH_TOKEN, authToken)
                .putBoolean(KEY_LOGGED_IN, true)
                .apply();
    }

    public boolean isLoggedIn() {
        return sharedPreferences.getBoolean(KEY_LOGGED_IN, false)
                && sharedPreferences.contains(KEY_EMAIL)
                && sharedPreferences.contains(KEY_AUTH_TOKEN);
    }

    public String getEmail() {
        return sharedPreferences.getString(KEY_EMAIL, null);
    }

    public String getAuthToken() {
        return sharedPreferences.getString(KEY_AUTH_TOKEN, null);
    }

    public void clearSession() {
        sharedPreferences.edit().clear().apply();
    }
}

package com.example.prototype;

public interface AuthCallback {
    void onSuccess(String authToken);
    void onError(String message);
}

package com.example.prototype;

import android.os.Handler;
import android.os.Looper;

public class AuthRepository {
    public void login(String email, String password, AuthCallback callback) {
        new Handler(Looper.getMainLooper()).postDelayed(() -> {
            if ("demo@example.com".equals(email) && "password123".equals(password)) {
                callback.onSuccess("demo_auth_token_abc123");
            } else {
                callback.onError("Invalid email or password");
            }
        }, 1000);
    }
}

package com.example.prototype;

import android.content.Intent;
import android.os.Bundle;
import android.text.TextUtils;
import android.widget.Button;
import android.widget.EditText;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

public class LoginActivity extends AppCompatActivity {
    private EditText emailInput;
    private EditText passwordInput;
    private SessionManager sessionManager;
    private AuthRepository authRepository;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        sessionManager = new SessionManager(this);
        authRepository = new AuthRepository();

        if (sessionManager.isLoggedIn()) {
            navigateToHome();
            finish();
            return;
        }

        setContentView(R.layout.activity_login);

        emailInput = findViewById(R.id.editTextEmail);
        passwordInput = findViewById(R.id.editTextPassword);
        Button loginButton = findViewById(R.id.buttonLogin);

        loginButton.setOnClickListener(v -> attemptLogin());
    }

    private void attemptLogin() {
        String email = emailInput.getText().toString().trim();
        String password = passwordInput.getText().toString();

        if (TextUtils.isEmpty(email)) {
            emailInput.setError("Email is required");
            emailInput.requestFocus();
            return;
        }

        if (TextUtils.isEmpty(password)) {
            passwordInput.setError("Password is required");
            passwordInput.requestFocus();
            return;
        }

        authRepository.login(email, password, new AuthCallback() {
            @Override
            public void onSuccess(String authToken) {
                sessionManager.saveLoginSession(email, authToken);
                Toast.makeText(LoginActivity.this, "Login successful", Toast.LENGTH_SHORT).show();
                navigateToHome();
                finish();
            }

            @Override
            public void onError(String message) {
                Toast.makeText(LoginActivity.this, message, Toast.LENGTH_SHORT).show();
            }
        });
    }

    private void navigateToHome() {
        startActivity(new Intent(this, HomeActivity.class));
    }
}

package com.example.prototype;

import android.content.Intent;
import android.os.Bundle;
import android.widget.Button;
import android.widget.TextView;

import androidx.appcompat.app.AppCompatActivity;

public class HomeActivity extends AppCompatActivity {
    private SessionManager sessionManager;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_home);

        sessionManager = new SessionManager(this);

        if (!sessionManager.isLoggedIn()) {
            redirectToLogin();
            finish();
            return;
        }

        TextView welcomeText = findViewById(R.id.textViewWelcome);
        Button logoutButton = findViewById(R.id.buttonLogout);

        String email = sessionManager.getEmail();
        welcomeText.setText("Welcome, " + (email != null ? email : "User"));

        logoutButton.setOnClickListener(v -> {
            sessionManager.clearSession();
            redirectToLogin();
            finish();
        });
    }

    private void redirectToLogin() {
        Intent intent = new Intent(this, LoginActivity.class);
        intent.addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP | Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
        startActivity(intent);
    }
}

